{
  "sentences": [
    {
      "text": "那個人長得很高，而且很瘦。",
      "pinyin": "Nà ge rén zhǎng de hěn gāo, érqiě hěn shòu.",
      "pinyin_numeric": "na4 ge ren2 zhang3 de hen3 gao1, er2 qie3 hen3 shou4.",
      "translation_en": "That person is very tall and also very thin.",
      "translation_ko": "그 사람은 키가 매우 크고, 또한 매우 날씬합니다."
    },
    {
      "text": "我妹妹長得很可愛，個性也很活潑。",
      "pinyin": "Wǒ mèimei zhǎng de hěn kě'ài, gèxìng yě hěn huópō.",
      "pinyin_numeric": "wo3 mei4 mei5 zhang3 de hen3 ke3 ai4, ge4 xing4 ye3 hen3 huo2 po1.",
      "translation_en": "My younger sister looks very cute, and her personality is also very lively.",
      "translation_ko": "제 여동생은 매우 귀엽게 생겼고, 성격도 매우 활발합니다."
    },
    {
      "text": "他看起來很年輕，可是已經三十歲了。",
      "pinyin": "Tā kàn qǐlái hěn niánqīng, kěshì yǐjīng sān shí suì le.",
      "pinyin_numeric": "ta1 kan4 qi3 lai2 hen3 nian2 qing1, ke3 shi4 yi3 jing1 san1 shi2 sui4 le5.",
      "translation_en": "He looks very young, but he is already thirty years old.",
      "translation_ko": "그는 매우 젊어 보이지만, 벌써 서른 살입니다."
    },
    {
      "text": "我哥哥長得很帥，而且個性很溫柔。",
      "pinyin": "Wǒ gēge zhǎng de hěn shuài, érqiě gèxìng hěn wēnróu.",
      "pinyin_numeric": "wo3 ge1 ge5 zhang3 de hen3 shuai4, er2 qie3 ge4 xing4 hen3 wen1 rou2.",
      "translation_en": "My older brother is very handsome, and his personality is very gentle.",
      "translation_ko": "제 오빠는 매우 잘생겼고, 성격도 매우 온화합니다."
    },
    {
      "text": "那個女生看起來很害羞，可是說話很大方。",
      "pinyin": "Nà ge nǚshēng kàn qǐlái hěn hàixiū, kěshì shuōhuà hěn dàfāng.",
      "pinyin_numeric": "na4 ge nü3 sheng1 kan4 qi3 lai2 hen3 hai4 xiu1, ke3 shi4 shuo1 hua4 hen3 da4 fang1.",
      "translation_en": "That girl looks very shy, but she speaks very generously.",
      "translation_ko": "그 여학생은 매우 수줍어 보이지만, 말을 할 때는 매우 대범합니다."
    },
    {
      "text": "我朋友長得不高，可是個性很幽默。",
      "pinyin": "Wǒ péngyou zhǎng de bù gāo, kěshì gèxìng hěn yōumò.",
      "pinyin_numeric": "wo3 peng2 you5 zhang3 de bu4 gao1, ke3 shi4 ge4 xing4 hen3 you1 mo4.",
      "translation_en": "My friend is not tall, but his personality is very humorous.",
      "translation_ko": "제 친구는 키가 크지 않지만, 성격이 매우 유머러스합니다."
    },
    {
      "text": "那個老師看起來很認真，而且很聰明。",
      "pinyin": "Nà ge lǎoshī kàn qǐlái hěn rènzhēn, érqiě hěn cōngmíng.",
      "pinyin_numeric": "na4 ge lao3 shi1 kan4 qi3 lai2 hen3 ren4 zhen1, er2 qie3 hen3 cong1 ming2.",
      "translation_en": "That teacher looks very serious, and also very smart.",
      "translation_ko": "그 선생님은 매우 진지해 보이고, 또한 매우 똑똑합니다."
    },
    {
      "text": "他長得很胖，可是個性很友善。",
      "pinyin": "Tā zhǎng de hěn pàng, kěshì gèxìng hěn yǒushàn.",
      "pinyin_numeric": "ta1 zhang3 de hen3 pang4, ke3 shi4 ge4 xing4 hen3 you3 shan4.",
      "translation_en": "He is very fat, but his personality is very friendly.",
      "translation_ko": "그는 매우 뚱뚱하지만, 성격은 매우 친절합니다."
    },
    {
      "text": "我姐姐長得很漂亮，而且眼睛很大。",
      "pinyin": "Wǒ jiějie zhǎng de hěn piàoliang, érqiě yǎnjīng hěn dà.",
      "pinyin_numeric": "wo3 jie3 jie5 zhang3 de hen3 piao4 liang5, er2 qie3 yan3 jing1 hen3 da4.",
      "translation_en": "My older sister is very beautiful, and her eyes are very big.",
      "translation_ko": "제 언니는 매우 예쁘게 생겼고, 눈도 매우 큽니다."
    },
    {
      "text": "那個人看起來很年輕，可是頭髮已經白了。",
      "pinyin": "Nà ge rén kàn qǐlái hěn niánqīng, kěshì tóufa yǐjīng bái le.",
      "pinyin_numeric": "na4 ge ren2 kan4 qi3 lai2 hen3 nian2 qing1, ke3 shi4 tou2 fa5 yi3 jing1 bai2 le5.",
      "translation_en": "That person looks very young, but their hair is already white.",
      "translation_ko": "그 사람은 매우 젊어 보이지만, 머리카락은 이미 하얗습니다."
    }
  ]
}
